<?php
namespace Tests\Feature;
use App\Domain\Inventory\Instances\ItemInstanceEventType;use App\Domain\Inventory\Instances\Refinement\ItemRefinementService;use App\Domain\Inventory\Instances\Refinement\RefinementTokenService;use App\Domain\Inventory\InventoryService;use App\Domain\Wallet\GoldReasonCode;use App\Domain\Wallet\WalletService;use App\Models\Character;use App\Models\CharacterItem;use App\Models\GoldTransaction;use App\Models\Item;use App\Models\ItemInstance;use App\Models\ItemInstanceEvent;use App\Models\RefinementLevel;use App\Models\RefinementLevelMaterial;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class ItemRefinementTest extends TestCase {use RefreshDatabase;private function setupRefinement(){ $character=Character::factory()->create();$equipment=Item::create(['code'=>'test_refinement_sword','name'=>'Testing Sword','item_type'=>'equipment','equipment_type'=>'weapon','rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'status'=>'active']);$material=Item::create(['code'=>'test_refinement_ore','name'=>'Testing Ore','item_type'=>'material','rarity'=>'common','is_stackable'=>true,'max_stack'=>99,'status'=>'active']);$instance=ItemInstance::factory()->create(['character_id'=>$character->id,'item_id'=>$equipment->id]);$rule=RefinementLevel::create(['from_level'=>0,'to_level'=>1,'success_chance_basis_points'=>10000,'gold_cost'=>10,'failure_behavior'=>'keep_level','status'=>'active']);RefinementLevelMaterial::create(['refinement_level_id'=>$rule->id,'item_id'=>$material->id,'quantity'=>2]);app(InventoryService::class)->addItem($character,$material,5);app(WalletService::class)->credit($character,20,GoldReasonCode::ADMIN_GRANT);return compact('character','equipment','material','instance','rule');}
public function test_refinement_is_atomic_audited_and_idempotent(){extract($this->setupRefinement());$token=app(RefinementTokenService::class)->issue($character,$instance);$first=app(ItemRefinementService::class)->refine($character,$instance,$token);$second=app(ItemRefinementService::class)->refine($character,$instance->fresh(),$token);$this->assertSame(1,$first->currentLevel());$this->assertSame($first->toArray(),$second->toArray());$this->assertSame(1,$instance->fresh()->refinement_level);$this->assertSame(3,(int)CharacterItem::where('character_id',$character->id)->where('item_id',$material->id)->value('quantity'));$this->assertSame(1,GoldTransaction::where('reason_code',GoldReasonCode::ITEM_REFINEMENT)->count());$this->assertSame(1,ItemInstanceEvent::where('event_type',ItemInstanceEventType::REFINEMENT_SUCCEEDED)->count());}
public function test_different_token_for_old_level_is_stale_without_double_consumption(){extract($this->setupRefinement());$one=app(RefinementTokenService::class)->issue($character,$instance);$two=app(RefinementTokenService::class)->issue($character,$instance);app(ItemRefinementService::class)->refine($character,$instance,$one);try{app(ItemRefinementService::class)->refine($character,$instance->fresh(),$two);$this->fail('Expected stale operation.');}catch(\InvalidArgumentException $e){$this->assertStringContainsString('stale',$e->getMessage());}$this->assertSame(1,$instance->fresh()->refinement_level);$this->assertSame(3,(int)CharacterItem::where('character_id',$character->id)->where('item_id',$material->id)->value('quantity'));}
public function test_invalid_probability_is_rejected(){ $this->expectException(\InvalidArgumentException::class);$rule=new RefinementLevel(['from_level'=>0,'to_level'=>1,'success_chance_basis_points'=>9999,'gold_cost'=>0,'failure_behavior'=>'keep_level','status'=>'active']);app(\App\Domain\Inventory\Instances\Refinement\RefinementRuleValidator::class)->validate($rule);}}
